const t=!0,richTypes={Date:t,RegExp:t,String:t,Number:t};export default function diff(t,e,c={cyclesFix:!0},r=[]){let s=[];for(const n in t){var p=t[n];const o=Array.isArray(t)?+n:n;if(n in e){var i=e[n],a="object"==typeof p&&"object"==typeof i;if(!(p&&i&&a)||richTypes[Object.getPrototypeOf(p).constructor.name]||c.cyclesFix&&r.includes(p))p===i||a&&(isNaN(p)?p+""==i+"":+p==+i)||s.push({path:[o],type:"CHANGE",value:i});else{const y=diff(p,i,c,c.cyclesFix?r.concat([p]):[]);s.push.apply(s,y.map(t=>(t.path.unshift(o),t)))}}else s.push({type:"REMOVE",path:[o]})}for(const f in e)f in t||s.push({type:"CREATE",path:[Array.isArray(e)?+f:f],value:e[f]});return s}